$oauth2 = new OAuth2($config)
$middleware = new AuthTokenMiddleware($oauth2);
$stack = HandlerStack::create();
$stack->push($middleware);

$client = new Client([
    'handler' => $stack,
    'base_uri' => 'https://www.googleapis.com/taskqueue/v1beta2/projects/',
